+#[derive(Debug, Clone, PartialEq, Eq)]
+pub struct ScreenDiagnosticSnapshot {
+    pub screen: String,
+    pub scope: String,
+    pub query_params: String,
+    pub raw_count: u64,
+    pub rendered_count: u64,
+    pub dropped_count: u64,
